    <div id="script-target-wrapper">
        <br>
        <b>DRIVERS Ticket Description</b>
        <div id="lang-script-target">
            <!-- This block of HTML and the script in it auto-populate the DRIVERS ticket description on page load. -->
            Script Target - If you can read this text, the script has failed
            <script>
                $.get('https://jira.mongodb.org/browse/DRIVERS-1437', function(data) {
                    var description = $(data).find("#description-val");
                    $("#lang-script-target").html(description);
                });
            </script>
        </div>
    </div>
{html}

